sql:
SELECT user_id, COUNT(*) AS total_trades
FROM trading_activity
GROUP BY user_id;

SELECT SUM(trade_fee)
FROM trading_activity
WHERE stock_id = 1;

SELECT AVG(close_price) AS avg_close_price
FROM historical_prices
WHERE date = '2016-01-05';

external_knowledge:
- "size" refers to the market capitalization;
- "identity tag" refers to the stock symbol;
- "helmsman" refers to the CEO;
- "volume of sails" metaphorically refers to the total volume traded;
- "average price at which the ship docked after adjusting for the wind" metaphorically refers to the average adjusted closing price.

sql:
SELECT COUNT(DISTINCT activity_id) AS Total_Trades, MAX(price_per_share) AS Max_Price_Per_Share
FROM trading_activity
WHERE trade_status = 'completed';
